+      const cached = await this.configTuning.cacheGet(key);
+      if (cached) {
+        this.stats.cacheHits++;
+        this.stats.totalTokensSaved += 100;
+        return cached as T;
+      }
     }

     this.stats.cacheMisses++;
     const result = await generator();
